"""Dynamic command generation for ctxcli.

Generates Typer commands from cached MCP tools at runtime.
"""

import asyncio
import json
from typing import Annotated, Any

import typer
from rich.console import Console

from context_surfaces.cli.ctxcli.config import ConfigManager, ProfileConfig
from context_surfaces.cli.ctxcli.transformer import TransformedCommand

console = Console()


def create_entity_app(
    entity: str,
    commands: list[TransformedCommand],
    config_manager: ConfigManager,
    profile_name: str,
) -> typer.Typer:
    """Create a Typer app for an entity with its commands.

    Args:
        entity: Entity name (e.g., "user")
        commands: List of transformed commands for this entity
        config_manager: Config manager instance
        profile_name: Active profile name

    Returns:
        Typer app with registered commands
    """
    entity_app = typer.Typer(
        name=entity,
        help=f"Commands for {entity}",
        no_args_is_help=True,
    )

    for cmd in commands:
        # Create and register command
        _register_command(entity_app, cmd, config_manager, profile_name)

    return entity_app


def _register_command(
    entity_app: typer.Typer,
    cmd: TransformedCommand,
    config_manager: ConfigManager,
    default_profile_name: str,
) -> None:
    """Register a single command on the entity app."""
    # Capture cmd in closure (but NOT profile - that's read at runtime from ctx.obj)
    captured_cmd = cmd
    captured_config = config_manager
    captured_default_profile = default_profile_name

    @entity_app.command(
        name=cmd.verb,
        help=cmd.description or f"{cmd.verb.title()} operation",
        context_settings={"allow_extra_args": True, "ignore_unknown_options": True},
    )
    def dynamic_command(
        ctx: typer.Context,
        output: Annotated[
            str,
            typer.Option("--output", "-o", help="Output format: table, json, yaml"),
        ] = "table",
        value: Annotated[str | None, typer.Option("--value", help="Value for filter operations")] = None,
        search_term: Annotated[str | None, typer.Option("--search-term", help="Search term")] = None,
        by: Annotated[str | None, typer.Option("--by", help="Field to filter by")] = None,
        limit: Annotated[int | None, typer.Option("--limit", help="Maximum results")] = None,
        offset: Annotated[int | None, typer.Option("--offset", help="Results offset")] = None,
        min_value: Annotated[float | None, typer.Option("--min-value", help="Minimum value for range")] = None,
        max_value: Annotated[float | None, typer.Option("--max-value", help="Maximum value for range")] = None,
    ) -> None:
        # Read profile from runtime context (set by --profile flag in main_callback)
        # Fall back to the default captured at module load time
        runtime_profile = ctx.obj.get("profile", captured_default_profile) if ctx.obj else captured_default_profile

        _execute_dynamic_command(
            ctx=ctx,
            cmd=captured_cmd,
            config_manager=captured_config,
            profile_name=runtime_profile,
            output=output,
            value=value,
            search_term=search_term,
            by=by,
            limit=limit,
            offset=offset,
            min_value=min_value,
            max_value=max_value,
        )


def _execute_dynamic_command(
    ctx: typer.Context,
    cmd: TransformedCommand,
    config_manager: ConfigManager,
    profile_name: str,
    output: str,
    value: str | None,
    search_term: str | None,
    by: str | None,
    limit: int | None,
    offset: int | None,
    min_value: float | None,
    max_value: float | None,
) -> None:
    """Execute a dynamic command."""
    # Read profile from runtime context (set by --profile flag in main_callback)
    # The profile_name parameter is the fallback (captured at registration time)
    runtime_profile = ctx.obj.get("profile", profile_name) if ctx.obj else profile_name
    profile = config_manager.get_profile(runtime_profile)

    # Show verbose info if requested
    verbose = ctx.obj.get("verbose", False) if ctx.obj else False
    if verbose:
        _show_verbose_context(runtime_profile, profile, cmd)

    _check_and_refresh_cache(config_manager, runtime_profile, profile)

    # Build arguments
    arguments = _build_arguments(
        cmd=cmd,
        ctx_args=ctx.args,
        value=value,
        search_term=search_term,
        by=by,
        limit=limit,
        offset=offset,
        min_value=min_value,
        max_value=max_value,
    )

    # Call the tool
    try:
        result = asyncio.run(_call_tool(profile.mcp_url, profile.agent_key, cmd.original_name, arguments))
        _render_output(result, output)
    except Exception as e:
        console.print(f"[bold red]Error:[/bold red] {e}")
        raise typer.Exit(code=1) from e


def _build_arguments(
    cmd: TransformedCommand,
    ctx_args: list[str],
    value: str | None,
    search_term: str | None,
    by: str | None,
    limit: int | None,
    offset: int | None,
    min_value: float | None,
    max_value: float | None,
) -> dict[str, Any]:
    """Build tool arguments from CLI parameters."""
    arguments: dict[str, Any] = {}

    # Add explicit params
    param_map = {
        "value": value,
        "query": search_term,
        "limit": limit,
        "offset": offset,
        "min_value": min_value,
        "max_value": max_value,
    }
    arguments.update({k: v for k, v in param_map.items() if v is not None})

    # Handle 'by' field — only include if the tool's schema actually has a 'by' property.
    # For tools like filter_customer_by_account_status, the field is encoded in the
    # tool name and the MCP tool only expects {"value": ...}, not {"by": ...}.
    schema_props = cmd.input_schema.get("properties", {})
    if by is not None and "by" in schema_props:
        arguments["by"] = by

    # Parse extra positional args
    extra_args = _parse_extra_args(ctx_args, cmd)
    arguments.update(extra_args)

    return arguments


def _show_verbose_context(
    profile_name: str,
    profile: ProfileConfig,
    cmd: TransformedCommand,
) -> None:
    """Show verbose connection context."""
    from datetime import datetime

    console.print("[dim]─── Connection Context ───[/dim]")
    console.print(f"[dim]Profile:[/dim] {profile_name}")
    console.print(f"[dim]MCP URL:[/dim] {profile.mcp_url}")
    console.print(f"[dim]Tool:[/dim] {cmd.original_name}")

    if profile.tools_cache:
        age = datetime.now() - profile.tools_cache.fetched_at
        hours = int(age.total_seconds() // 3600)
        minutes = int((age.total_seconds() % 3600) // 60)
        console.print(f"[dim]Cache age:[/dim] {hours}h {minutes}m")
        console.print(f"[dim]Tools cached:[/dim] {len(profile.tools_cache.tools)}")

    console.print("[dim]───────────────────────────[/dim]\n")


def _parse_extra_args(args: list[str], cmd: TransformedCommand) -> dict[str, Any]:
    """Parse extra CLI arguments into tool arguments."""
    result: dict[str, Any] = {}
    positional_params = cmd.get_positional_args()
    schema_props = cmd.input_schema.get("properties", {})
    positional_idx = 0

    i = 0
    while i < len(args):
        arg = args[i]
        if arg.startswith("--"):
            key = arg[2:].replace("-", "_")
            if i + 1 < len(args) and not args[i + 1].startswith("--"):
                expected_type = schema_props.get(key, {}).get("type")
                result[key] = _coerce_value(args[i + 1], expected_type)
                i += 2
            else:
                result[key] = True
                i += 1
        elif not arg.startswith("-"):
            # Positional argument
            if positional_idx < len(positional_params):
                param_name = positional_params[positional_idx]
                expected_type = schema_props.get(param_name, {}).get("type")
                result[param_name] = _coerce_value(arg, expected_type)
                positional_idx += 1
            i += 1
        else:
            i += 1

    return result


def _coerce_value(value: str, expected_type: str | None = None) -> Any:
    """Coerce a string value to the expected type from the schema.

    Args:
        value: Raw string value from CLI
        expected_type: Expected type from the tool's input schema

    Returns:
        Value coerced to the correct type
    """
    if expected_type == "string":
        return value
    if expected_type == "integer":
        try:
            return int(value)
        except ValueError:
            return value
    if expected_type == "number":
        try:
            return float(value)
        except ValueError:
            return value
    if expected_type == "boolean":
        return value.lower() in ("true", "1", "yes")

    # No schema type info — try JSON parsing but keep strings as strings
    try:
        return json.loads(value)
    except json.JSONDecodeError:
        return value


def _check_and_refresh_cache(
    config_manager: ConfigManager,
    profile_name: str,
    profile: ProfileConfig,
) -> None:
    """Check cache TTL and refresh if expired."""
    if not (profile.tools_cache and profile.tools_cache.is_expired()):
        return

    console.print("[dim]Tools cache expired, refreshing...[/dim]")
    try:
        _do_refresh_cache(config_manager, profile_name, profile)
    except Exception as e:
        console.print(f"[yellow]Warning:[/yellow] Failed to refresh cache: {e}")
        console.print("[dim]Using stale cache[/dim]")


def _do_refresh_cache(
    config_manager: ConfigManager,
    profile_name: str,
    profile: ProfileConfig,
) -> None:
    """Perform the actual cache refresh."""
    from datetime import datetime

    from context_surfaces.cli.ctxcli.commands.tools import _fetch_tools
    from context_surfaces.cli.ctxcli.config import ToolsCache, ToolSchema

    tools = asyncio.run(_fetch_tools(profile.mcp_url, profile.agent_key))
    profile.tools_cache = ToolsCache(
        fetched_at=datetime.now(),
        tools=[
            ToolSchema(
                name=t.get("name", ""),
                description=t.get("description", ""),
                input_schema=t.get("inputSchema", {}),
            )
            for t in tools
        ],
    )
    config_manager.set_profile(profile_name, profile)
    console.print(f"[dim]Refreshed {len(tools)} tools[/dim]")


def _render_output(result: Any, output_format: str) -> None:
    """Render the result in the specified format."""
    if output_format == "json":
        print(json.dumps(result, indent=2, default=str))
    elif output_format == "yaml":
        import yaml

        print(yaml.safe_dump(result, default_flow_style=False))
    else:  # table
        _render_table(result)


def _render_table(data: Any) -> None:
    """Render data as a rich table."""
    # Try to unwrap MCP response format
    unwrapped = _unwrap_mcp_response(data)
    if unwrapped is not None:
        _render_table(unwrapped)
        return

    if isinstance(data, dict):
        _render_dict_as_table(data)
    elif isinstance(data, list):
        _render_list_as_table(data)
    else:
        console.print(str(data))


def _unwrap_mcp_response(data: Any) -> Any | None:
    """Try to unwrap MCP response format. Returns None if not MCP format."""
    if not isinstance(data, dict):
        return None
    content = data.get("content")
    if not isinstance(content, list) or len(content) == 0:
        return None
    first = content[0]
    if not isinstance(first, dict) or "text" not in first:
        return None
    try:
        return json.loads(first["text"])
    except (json.JSONDecodeError, TypeError):
        return None


def _render_dict_as_table(data: dict) -> None:
    """Render a dict as a key/value table."""
    from rich.table import Table

    table = Table(show_header=True, header_style="bold")
    table.add_column("Field")
    table.add_column("Value")
    for key, value in data.items():
        table.add_row(str(key), str(value))
    console.print(table)


def _render_list_as_table(data: list) -> None:
    """Render a list as a table."""
    from rich.table import Table

    if len(data) == 0:
        console.print("[dim]No results[/dim]")
        return

    if isinstance(data[0], dict):
        table = Table(show_header=True, header_style="bold")
        columns = list(data[0].keys())
        for col in columns:
            table.add_column(col)
        for row in data:
            table.add_row(*[str(row.get(col, "")) for col in columns])
        console.print(table)
    else:
        for item in data:
            console.print(str(item))


async def _call_tool(mcp_url: str, agent_key: str, tool_name: str, arguments: dict) -> Any:
    """Call an MCP tool."""
    from context_surfaces.mcp_client import MCPClient

    async with MCPClient(mcp_url=mcp_url, agent_key=agent_key) as mcp:
        return await mcp.call_tool(tool_name, arguments)

